/* === DOU DAYS 2026 PRESENTATION STYLES === */

/* Presentation Container */
.presentation {
  width: 100vw;
  height: var(--vh-full);
  background: var(--dou-bg-gradient);
  color: var(--dou-white);
  font-family: var(--font-sans);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  position: relative;
}

/* === SLIDE CONTAINER === */
.slide-container {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: var(--space-lg) var(--space-xl);
  position: relative;
  overflow: hidden;
}

/*
 * Staged slide container: removes padding so the scaled 1920×1080 stage can
 * fill the full height between the header (none) and the bottom input bar.
 * Applied to any slide with `chrome: 'hero'` or `chrome: 'global'`.
 */
.slide-container--staged {
  padding: 0;
}

/* === SLIDE === */
.slide {
  width: 100%;
  max-width: 1600px;
  max-height: 100%;
  overflow: hidden;
  color: var(--dou-white);
  font-family: var(--font-sans);
  text-align: center;
  animation: slideIn var(--transition-normal) cubic-bezier(0.16, 1, 0.3, 1);
}

@keyframes slideIn {
  from {
    opacity: 0;
    transform: translateY(20px);
    filter: blur(4px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
    filter: blur(0);
  }
}

/* Headings */
.slide h1 {
  font-size: var(--font-size-h1);
  font-weight: 600;
  color: var(--dou-magenta);
  margin-bottom: var(--space-lg);
  letter-spacing: var(--letter-spacing-tight);
  line-height: var(--line-height-tight);
  font-family: var(--font-sans);
}

.slide h1.hero {
  font-size: var(--font-size-hero);
}

.slide h2 {
  font-size: var(--font-size-h2);
  font-weight: 700;
  color: var(--dou-mint);
  margin-bottom: var(--space-lg);
  letter-spacing: var(--letter-spacing-tight);
  line-height: 1;
  font-family: var(--font-sans);
}

.slide h3 {
  font-size: var(--font-size-h3);
  font-weight: 600;
  color: var(--dou-white);
  margin-bottom: var(--space-md);
  line-height: var(--line-height-tight);
  font-family: var(--font-sans);
}

/* Paragraphs */
.slide p {
  font-size: var(--slide-text-normal);
  line-height: var(--slide-line-height-normal);
  margin-bottom: var(--space-md);
  color: var(--dou-white-dim);
  font-family: var(--font-sans);
}

.slide p strong,
.slide p b {
  color: var(--dou-white);
  font-weight: 700;
}

.slide p em {
  color: var(--dou-magenta);
  font-style: normal;
  font-weight: 600;
}

/* Lists */
.slide ul,
.slide ol {
  list-style: none;
  text-align: left;

