          {/* Bullets */}
          <div
            style={{
              flex: 1,
              textAlign: 'left',
              background: 'rgba(10,14,20,0.8)',
              borderRadius: '10px',
              padding: '0.75rem 1rem',
              backdropFilter: 'blur(4px)',
              border: '1px solid rgba(255,255,255,0.07)',
            }}
          >
            <SlideItem delay={0.05}>
